#include <stdio.h>

int main() {
    int T;
    if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        int r1, r2, r3, r4;
        scanf("%d %d %d %d", &r1, &r2, &r3, &r4);
        if (r1 == 0 && r2 == 0 && r3 == 0 && r4 == 0)
            printf("IN\n");
        else
            printf("OUT\n");
    }
    return 0;
}

