#!/usr/bin/env python3
import sys

def solve():
    data = sys.stdin.read().strip().split()
    if not data:
        return
    it = iter(data)
    T = int(next(it))
    out_lines = []
    for _ in range(T):
        r1 = int(next(it)); r2 = int(next(it)); r3 = int(next(it)); r4 = int(next(it))
        if r1 == 0 and r2 == 0 and r3 == 0 and r4 == 0:
            out_lines.append("IN")
        else:
            out_lines.append("OUT")
    sys.stdout.write("\n".join(out_lines))

if __name__ == "__main__":
    solve()

